    public function actionSyncCourse()
    {
        $storeSalekit = ElearningStore::find()->where(['type' => ElearningStore::SALEKIT])->one();
        if (!empty($storeSalekit)) {
            $courseIds = MCourse::find()->select('ID')
                ->where(['Status' => MCourse::STATUS_PUBLISH])
                ->andWhere(['>=', 'Updated_at', Carbon::now()->subDay()])
                ->column();
            if (count($courseIds) > 0) {
                ElearningStoreCourse::syncQueue($storeSalekit->id, $courseIds);
                $noteIds = implode(',', $courseIds);
                Helper_bonus::saveLog([
                    [MLogSystem::SALEKIT, time(), $storeSalekit->id, 'Đồng bộ tự động các khóa học thay đổi: '. $noteIds , 1]
                ]);
            }
            $comboIds = MCombo::find()->select('ID')
                ->where(['Status' => MCombo::STATUS])
                ->andWhere(['>', 'Price', 0])
                ->andWhere(['>=', 'Last_update', Carbon::now()->subDay()])
                ->andWhere(['Learn_months' => MCombo::LEARN_FOREVER])
                ->column();
            if (count($comboIds) > 0) {
                ElearningStoreCourse::syncComboQueue($storeSalekit, $comboIds);
            }
            Helper_bonus::saveLog([
                [MLogSystem::SALEKIT, time(), $storeSalekit->id, 'Không có khóa học thay đổi' , 1]
            ]);
        }
    }

