    public function actionSyncOrder()
    {
        $storeSalekit = ElearningStore::find()->where(['type' => ElearningStore::SALEKIT])->one();
        if (!empty($storeSalekit)) {
            $orderIds = MOrder::find()->select('ID')
                ->where(['!=', 'HandleStatus', MOrder::ORDER_STATUS_DELETED])
                ->andWhere(['>=', 'updated_time', Carbon::now()->subMinutes(6)])
                ->column();
            if (count($orderIds) > 0) {
                ElearningStoreOrder::syncQueue($storeSalekit->id, $orderIds);
            }
            $deletedOrderIds = MOrder::find()->select('order.ID')
                ->leftJoin('elearning_store_order', 'order.ID = elearning_store_order.order_id')
                ->where(['order.HandleStatus' => MOrder::ORDER_STATUS_DELETED, 'store_id' => $storeSalekit->id])
                ->andWhere(['!=', 'elearning_store_order.shop_order_id', 0])
                ->column();
            if (count($deletedOrderIds) > 0) {
                ElearningStoreOrder::syncQueue($storeSalekit->id, $deletedOrderIds);
