    public function salekitQueue($elearing, $store)
    {
        if (!empty($elearing->course_id)) {
            $course = MCourse::findOne($elearing->course_id);
            $token = $store->access_token;
            $salekit =  new SalekitStore();

            if ($elearing->status == false) {
                $response = $salekit->createProduct($token, $course);
