                    $elearing->sync_time = Carbon::now()->format('Y-m-d H:i:s');
                    $elearing->status = true;
                    $elearing->note = 'Cập nhật khóa học thành công - ' . $elearing->product_id;
                    $elearing->save(false);
                }
            }
        } elseif (!empty($elearing->combo_id)) {
            $combo = MCombo::findOne($elearing->combo_id);
            $token = $store->access_token;
            $salekit =  new SalekitStore();

            if ($elearing->status == false) {
                $response = $salekit->createCombo($store, $combo);
                if ($response['error']) {
                    $elearing->note = 'Error: ' . $response['msg'];
