                    $elearing->product_id = $response['data']->combo_id;
                    $elearing->sync_time = Carbon::now()->format('Y-m-d H:i:s');
                    $elearing->status = true;
                    $elearing->note = 'Tạo mới combo thành công - ' . $elearing->product_id;
