                $response = $salekit->updateCombo($store, $combo, $elearing->product_id);
                if ($response['error']) {
                    $elearing->note = 'Error: ' . $response['msg'];
                    $elearing->save(false);
                } else {
                    $elearing->sync_time = Carbon::now()->format('Y-m-d H:i:s');
                    $elearing->status = true;
                    $elearing->note = 'Cập nhật combo thành công - ' . $elearing->product_id;
                    $elearing->save(false);
                }
            }
        }

    }

    public function salekitOrderQueue($elearningOrder, $store)
    {
        if (!empty($elearningOrder->order_id)) {
            $order = MOrder::findOne($elearningOrder->order_id);
            $salekit = new SalekitStore();

            if (empty($elearningOrder->shop_order_id)) {
                $response = $salekit->createOrder($store, $order);
                if ($response['error']) {
                    $elearningOrder->note = 'Error: ' . $response['msg'];
                    $elearningOrder->save(false);
                } else {
                    $elearningOrder->shop_order_id = $response['data']->id;
                    $elearningOrder->sync_time = Carbon::now()->format('Y-m-d H:i:s');
                    $elearningOrder->note = 'Tạo mới đơn hàng thành công - ' . $elearningOrder->shop_order_id;
                    $elearningOrder->save(false);
                }
            } else {
                $response = $salekit->updateOrder($store, $order, $elearningOrder->shop_order_id);
                if ($response['error']) {
                    $elearningOrder->note = 'Error: ' . $response['msg'];
                    $elearningOrder->save(false);
                } else {
                    $elearningOrder->sync_time = Carbon::now()->format('Y-m-d H:i:s');
                    $elearningOrder->note = 'Cập nhật đơn hàng thành công - ' . $elearningOrder->shop_order_id;
                    $elearningOrder->save(false);
                }
            }
        }
    }

    public function getTtr()
    {
        return 2*60;
    }

    public function canRetry($attempt, $error)
    {
        return $attempt < 3;
    }
