                    ->save($path . $filename_medium, ['quality' => 100]);
                Image::thumbnail($path . $filename_medium, 400, 200)->save($path . $filename_medium, ['quality' => 100]);
            } else {
                $this->Banner_large = $this->getOldAttribute('Banner_large');
                $this->Banner_small = $this->getOldAttribute('Banner_small');
            }
        }
        return parent::beforeSave($insert);
    }

